Checks triangle count, surface area, manifold integrity, and face normal
consistency. Accepts a single STL file path as a command-line argument and
prints a JSON object: {"valid": true/false, "issues": [...]}.

Binary STL format:
  80-byte header
  4-byte uint32 triangle count
  Per triangle: 12-byte normal + 3x12-byte vertices + 2-byte attribute
"""
import json
import math
import struct
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def _is_binary_stl(path: str) -> bool:
    """Detect whether an STL file is binary or ASCII.

    Binary STL files have an 80-byte header followed by a 4-byte triangle count.
    ASCII STL files start with 'solid'.

    Note: Some binary STL files start with 'solid' in the header, so we also
    validate the declared triangle count against the file size.
    """
    try:
        with open(path, 'rb') as f:
            header = f.read(80)
            if len(header) < 80:
                return False  # too short for binary
            count_bytes = f.read(4)
            if len(count_bytes) < 4:
                return False
            triangle_count = struct.unpack('<I', count_bytes)[0]
            # Each triangle is 50 bytes (12+12+12+12+2)
            f.seek(0, 2)  # seek to end
            file_size = f.tell()
            expected_size = 80 + 4 + triangle_count * 50
            if file_size == expected_size and triangle_count > 0:
                return True
            # Check if it starts with 'solid' keyword (ASCII indicator)
            text_start = header.lstrip(b'\x00').decode('ascii', errors='replace').strip()
            if text_start.lower().startswith('solid'):
                return False
            # If size doesn't match ASCII pattern, try binary
            return file_size == expected_size
    except Exception:
        return False


