    """Parse a binary STL file and return triangles list."""
    issues = []
    triangles = []

    with open(path, 'rb') as f:
        header = f.read(80)  # skip header
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            issues.append("Binary STL: file too short to read triangle count")
            return {"issues": issues, "triangles": []}

        triangle_count = struct.unpack('<I', count_bytes)[0]

        for idx in range(triangle_count):
            data = f.read(50)  # 12+12+12+12+2 bytes
            if len(data) < 50:
                issues.append(f"Binary STL: unexpected end of file at triangle {idx}")
                break

            # Unpack normal and 3 vertices (each is 3 floats)
            values = struct.unpack('<12f', data[:48])
            # attribute byte count (2 bytes, ignored)

            normal = (values[0], values[1], values[2])
            v1 = (values[3], values[4], values[5])
            v2 = (values[6], values[7], values[8])
            v3 = (values[9], values[10], values[11])

            triangles.append((normal, [v1, v2, v3]))

    return {"issues": issues, "triangles": triangles}


