    """Parse an ASCII STL file and return triangles list."""
    issues = []
    triangles = []

    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith('facet normal'):
            parts = line.split()
