        if similarity < -0.99:
            inverted_count += 1

    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")
    if inverted_count > 0:
        issues.append(
            f"{inverted_count} face normal(s) are inverted relative to winding order"
